var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"대단하군요. 스캐빈저가 함대를 몰고 와도 뚫지 못했던 방어라인을 단신으로…","JPN":"すごいですね。スカベンジャーが艦隊を率いても突破できなかった防御ラインを単身で……","ENG":"Amazing. The Scavengers brought their fleet and couldn't get through the defense line. But you did it alone...","TWN":"太厲害了。竟然隻身一人突破了連清道夫艦隊也無能為力的防線。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"고작 죄수 몇 명 가두는 용도치곤 제법 넓군.","JPN":"たかが囚人を数人閉じ込めているにしては、随分と広いのだな。","ENG":"Quite spacious for a section that's only supposed to contain a few prisoners.","TWN":"只是囚禁幾個囚犯竟然要動用這麼大的空間。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"수감실은 어디지?","JPN":"収監室はどこだ？","ENG":"Where are the cells?","TWN":"牢房在哪裡？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"저기요.","JPN":"あの～。","ENG":"Hello?","TWN":"打擾一下。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_METAL_KNOCK"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"방금 심상치 않은 진동이 느껴졌는데- 밖에 뭔 일 있나요?","JPN":"今尋常じゃない地響きを感じたんですけど、外で何かありました？","ENG":"I just felt a strange vibration... Is something happening outside?","TWN":"我剛剛感覺到不尋常的振動，外面出什麼事了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쯧, 대답할 리 없나?","JPN":"チッ、答えるわけないか。","ENG":"Tsk, foolish of me to expect an answer.","TWN":"唉，果然沒人回答。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"1킬로평방미터 이내로 생명체 하나 없는 독방이라니, 거 조심성 한 번 대-단하시네.","JPN":"1平方キロメートル以内に生命体が一つもない独房なんて、素晴らしい危機管理意識だな。","ENG":"A solitary cell without any lifeforms within 1 square kilometer. Sooo cautious.","TWN":"方圓一公里內沒有任何生物的單人牢房，真是夠謹慎。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"망할, 그 여자만 아니었어도 지금쯤 북방합의체에서 재밌는 간첩놀이 하면서 놀고 있었을 텐데.","JPN":"くそっ、あの女さえいなければ、今頃北方合意体で楽しくスパイごっこしながら遊んでるはずだったのに。","ENG":"Dammit, if it weren't for that woman I'd be playing spy in the Northern Union right now.","TWN":"該死，要不是那個女人，我應該還在北方和議會玩著有趣的間諜遊戲吧。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아니지, 아니지. 그게 아니라 일단 세상이 끝장나는 걸 걱정해야 하나?","JPN":"いやいや。今は一応、世界が終わることを心配するべきかな？","ENG":"No, no. Maybe I should worry about the world ending first.","TWN":"不，不，是應該先擔心世界末日嗎？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어차피 그 사냥꾼이 있으니 제멋대로 활개치고 다니진 못할 텐데…","JPN":"どうせあの狩人のせいで、好き勝手に遊び回れはしないか……","ENG":"But that hunter wouldn't let anyone run around freely...","TWN":"反正既然有那麼獵人在，應該不能太過於隨心所欲。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그 자식… 대체 무슨 배짱으로 이 사단을 벌인 거야?","JPN":"あいつ……いったいなんでこんなことしたんだ？","ENG":"That bitch... What was she thinking, starting all this?","TWN":"那個混蛋……她有什麼膽量惹出這麼大的事端？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하아, 애초에 이런 진지한 고민은 내 분야가 아니라고.","JPN":"はあ……こんな真面目に悩み事するなんて、あたしには無理だ。","ENG":"*Sigh.* Thinking about serious stuff isn't really my specialty.","TWN":"唉，這種嚴肅的思考不是我的專長。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"자꾸 생각이란 걸 하니까 당 떨어지네.","JPN":"ずっと考えてたら糖分足りなくなっちゃったよ。","ENG":"My blood sugar is getting lower by thinking.","TWN":"越想越累，我得補充一下糖分。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"사탕… 먹을 수 있을 때 많이 먹어 둘 걸.","JPN":"キャンディー……食べられる時にいっぱい食べておくべきだったな。","ENG":"I should've eaten as many candies as I could back when I had the chance.","TWN":"糖果……早知道就多吃些了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"저기요- 층간소음이 너무 심한데요. 아무리 죄수라지만 여긴 생활권도 보장 안 해주나?","JPN":"すみませーん、うるさいんですけど！　囚人だからって、人としての生活も保障してくれないの？","ENG":"Hey. The people upstairs are really noisy. I know I'm a prisoner, but don't I at least have the right to reflect in peace?","TWN":"喂喂，這裡的隔音也太差了。就算是囚犯也應該得到最基本的生活權保障吧？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_METAL_KNOCK"},{"id":"L28_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"애초에 이 큐브 덩어리에 층이라는 게 있긴 한 거야? 눈 가리고 들어와서 구조도 전혀 모르겠다고.","JPN":"大体、このキューブの塊に階とかあるの？　目隠しして入ったから、構造も全然わかんないし。","ENG":"Does this Cube thing even have floors? I was blinded when I came in, so I don't even know the structure.","TWN":"話說這個魔方到底是什麼結構？進來的時候被蒙住了眼睛，什麼都沒看清楚。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"시계도 없어서 시간이 얼마나 흘렀는지도 모르겠어.","JPN":"時計もないから、時間の経過もさっぱりわかんないや。","ENG":"I can't even tell the time because I don't have a watch.","TWN":"而且連個時鐘也沒有，不知道過了多長時間。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이미 그 여자가 뚜껑이란 뚜껑은 다 열어버리고 이미 세상도 망해버린 거 아냐?","JPN":"既にあの女がフタを全部開けて、世界は滅びてたりして？","ENG":"Maybe that woman opened every casket she could find and the world ended.","TWN":"那個女人是不是早就把門都打開了，世界也已經滅亡了？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어디서 백마 탄 왕자라도 나타나서 나 좀 구해줬으면 좋겠네.","JPN":"どっからか白馬の王子様でも現われて、あたしのことを救ってくれないかな。","ENG":"Where's my Prince Charming at a time like this?","TWN":"真希望能有一位白馬王子過來把我救出去。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아니, 심심해 죽겠으니까 오크든 원숭이든 상관없으니 뭐라도 좀 튀어나와주라-","JPN":"にしても暇すぎぃ！　オークでもサルでもなんでもいいから出て来てよ～。","ENG":"At this point, even an orc or a monkey is fine. I'm bored–","TWN":"不不，不管是獸人還是猴子都無所謂，快來找我玩吧，快無聊死了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"우왓, 깜짝이야!","JPN":"うわっ、びっくりした！","ENG":"Whoa! The hell?!","TWN":"哇，嚇我一跳！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이건 뭐야? 로봇 대가리?","JPN":"これ何？　ロボットの頭？","ENG":"What's this? A robot head?","TWN":"這是什麼？機器人的頭？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PRIME_NPC_PRISON_MECH","text":{"KOREA":"경고, 경고…","JPN":"警告、警告……","ENG":"Warning. Warning...","TWN":"警告，警告……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_ELECTRIC_02"},{"id":"L38_1","type":"dialog","speaker":"PRIME_NPC_PRISON_MECH","text":{"KOREA":"경…… 고…….","JPN":"警……告……","ENG":"Warn... ing...","TWN":"警……告……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"에이미 양…?","JPN":"エイミーさん……？","ENG":"Amy...?","TWN":"艾米……？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"백마…?","JPN":"王子様……？","ENG":"Charming...?","TWN":"白馬……？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};